{"path":"/home/erik/Projects/minify/Sources/Models.swift","content":"import Foundation
import UniformTypeIdentifiers

struct InputImage: Identifiable, Hashable {
    let id = UUID()
    let url: URL
    let byteCount: Int64
}

enum OutputFormat: String, CaseIterable, Identifiable {
    case webp
    case png
    case jpg
    case heic
    case tiff

    var id: String { rawValue }

    var displayName: String {
        switch self {
        case .webp: return "WebP"
        case .png: return "PNG"
        case .jpg: return "JPEG"
        case .heic: return "HEIC"
        case .tiff: return "TIFF"
        }
    }

    var fileExtension: String {
        switch self {
        case .webp: return "webp"
        case .png: return "png"
        case .jpg: return "jpg"
        case .heic: return "heic"
        case .tiff: return "tiff"
        }
    }

    var fallback: OutputFormat {
        switch self {
        case .webp: return .jpg
        default: return self
        }
    }

    var preferredUTType: UTType? {
        switch self {
        case .webp:
            if #available(macOS 14.0, *) {
                return .webP
            }
            return nil
        case .png: return .png
        case .jpg: return .jpeg
        case .heic:
            if #available(macOS 11.0, *) {
                return .heic
            }
            return nil
        case .tiff: return .tiff
        }
    }
}

struct ConversionResult: Identifiable {
    let id = UUID()
    let source: URL
    let destination: URL
    let originalBytes: Int64
    let outputBytes: Int64

    var savingsPercent: Double {
        guard originalBytes > 0 else { return 0 }
        return max(0, (1 - Double(outputBytes) / Double(originalBytes)) * 100)
    }
}
"}

{"path":"/home/erik/Projects/minify/Sources/ImageConversionService.swift","content":"import AppKit
import Foundation
import ImageIO
import UniformTypeIdentifiers

struct ImageConversionService {
    enum ConversionError: Error, LocalizedError {
        case imageLoadFailed(URL)
        case destinationCreateFailed(URL)
        case finalizeFailed(URL)

        var errorDescription: String? {
            switch self {
            case .imageLoadFailed(let url):
                return "Could not load image: \(url.lastPathComponent)"
            case .destinationCreateFailed(let url):
                return "Could not create destination for: \(url.lastPathComponent)"
            case .finalizeFailed(let url):
                return "Could not write output: \(url.lastPathComponent)"
            }
        }
    }

    func estimateOutputBytes(for images: [InputImage], format: OutputFormat, quality: Double) -> Int64 {
        guard !images.isEmpty else { return 0 }

        let factor: Double = switch format {
        case .jpg, .webp, .heic:
            0.2 + (quality * 0.9)
        case .png:
            0.65 + (quality * 0.55)
        case .tiff:
            0.8 + (quality * 0.8)
        }

        let total = images.reduce(Int64(0)) { $0 + $1.byteCount }
        return Int64(Double(total) * factor)
    }

    func convert(
        images: [InputImage],
        format: OutputFormat,
        quality: Double,
        outputFolder: URL
    ) throws -> [ConversionResult] {
        try FileManager.default.createDirectory(at: outputFolder, withIntermediateDirectories: true)

        var results: [ConversionResult] = []

        for image in images {
            let outFormat = resolvedFormat(for: format)
            let ext = outFormat.fileExtension
            let destinationURL = outputFolder
                .appendingPathComponent(image.url.deletingPathExtension().lastPathComponent)
                .appendingPathExtension(ext)

            try convertSingle(
                inputURL: image.url,
                destinationURL: destinationURL,
                format: outFormat,
                quality: quality
            )

            let attrs = try FileManager.default.attributesOfItem(atPath: destinationURL.path)
            let outputBytes = (attrs[.size] as? NSNumber)?.int64Value ?? 0

            results.append(
                ConversionResult(
                    source: image.url,
                    destination: destinationURL,
                    originalBytes: image.byteCount,
                    outputBytes: outputBytes
                )
            )
        }

        return results
    }

    private func resolvedFormat(for requested: OutputFormat) -> OutputFormat {
        if requested == .webp {
            if #available(macOS 14.0, *), UTType.webP.identifier.isEmpty == false {
                return .webp
            }
            return requested.fallback
        }

        if requested == .heic, requested.preferredUTType == nil {
            return .jpg
        }

        return requested
    }

    private func convertSingle(
        inputURL: URL,
        destinationURL: URL,
        format: OutputFormat,
        quality: Double
    ) throws {
        guard
            let source = CGImageSourceCreateWithURL(inputURL as CFURL, nil),
            let cgImage = CGImageSourceCreateImageAtIndex(source, 0, nil)
        else {
            throw ConversionError.imageLoadFailed(inputURL)
        }

        let typeIdentifier = (format.preferredUTType ?? format.fallback.preferredUTType ?? .jpeg).identifier as CFString

        guard let destination = CGImageDestinationCreateWithURL(destinationURL as CFURL, typeIdentifier, 1, nil) else {
            throw ConversionError.destinationCreateFailed(destinationURL)
        }

        var properties: [CFString: Any] = [:]
        switch format {
        case .jpg, .webp, .heic:
            properties[kCGImageDestinationLossyCompressionQuality] = quality
        case .png:
            properties[kCGImageDestinationLossyCompressionQuality] = min(1.0, max(0.0, quality))
        case .tiff:
            properties[kCGImageDestinationLossyCompressionQuality] = quality
        }

        CGImageDestinationAddImage(destination, cgImage, properties as CFDictionary)

        guard CGImageDestinationFinalize(destination) else {
            throw ConversionError.finalizeFailed(destinationURL)
        }
    }
}
"}

{"path":"/home/erik/Projects/minify/Sources/MinifyViewModel.swift","content":"import AppKit
import Foundation
import SwiftUI

@MainActor
final class MinifyViewModel: ObservableObject {
    @Published var images: [InputImage] = []
    @Published var outputFormat: OutputFormat = .webp
    @Published var quality: Double = 0.72
    @Published var estimatedSize: Int64 = 0
    @Published var conversionResults: [ConversionResult] = []
    @Published var isConverting = false
    @Published var statusMessage: String = "Drop or pick images to begin."
    @Published var lastError: String?

    private let service = ImageConversionService()

    func pickImages() {
        let panel = NSOpenPanel()
        panel.canChooseFiles = true
        panel.canChooseDirectories = false
        panel.allowsMultipleSelection = true
        panel.allowedContentTypes = [.image]

        if panel.runModal() == .OK {
            addImageURLs(panel.urls)
        }
    }

    func clearImages() {
        images.removeAll()
        conversionResults.removeAll()
        recalculateEstimate()
        statusMessage = "Selection cleared."
    }

    func addImageURLs(_ urls: [URL]) {
        let fresh = urls.compactMap { url -> InputImage? in
            guard let attrs = try? FileManager.default.attributesOfItem(atPath: url.path),
                  let size = (attrs[.size] as? NSNumber)?.int64Value else { return nil }
            return InputImage(url: url, byteCount: size)
        }

        let merged = Array(Set(images + fresh)).sorted { $0.url.lastPathComponent < $1.url.lastPathComponent }
        images = merged
        recalculateEstimate()
        statusMessage = "Loaded \(images.count) image(s)."
    }

    func recalculateEstimate() {
        estimatedSize = service.estimateOutputBytes(for: images, format: outputFormat, quality: quality)
    }

    func convertAll() {
        guard !images.isEmpty else {
            statusMessage = "Select at least one image first."
            return
        }

        let panel = NSOpenPanel()
        panel.canChooseFiles = false
        panel.canChooseDirectories = true
        panel.canCreateDirectories = true
        panel.prompt = "Choose Output Folder"

        guard panel.runModal() == .OK, let folder = panel.url else { return }

        isConverting = true
        lastError = nil
        statusMessage = "Converting \(images.count) image(s)..."

        Task {
            do {
                let results = try service.convert(images: images, format: outputFormat, quality: quality, outputFolder: folder)
                conversionResults = results
                let totalIn = results.reduce(Int64(0)) { $0 + $1.originalBytes }
                let totalOut = results.reduce(Int64(0)) { $0 + $1.outputBytes }
                statusMessage = "Done. \(ByteCountFormatter.string(fromByteCount: totalIn, countStyle: .file)) → \(ByteCountFormatter.string(fromByteCount: totalOut, countStyle: .file))"
            } catch {
                lastError = error.localizedDescription
                statusMessage = "Conversion failed."
            }
            isConverting = false
        }
    }
}
"}

{"path":"/home/erik/Projects/minify/Sources/ContentView.swift","content":"import SwiftUI

struct ContentView: View {
    @ObservedObject var viewModel: MinifyViewModel

    var body: some View {
        ZStack {
            LinearGradient(
                colors: [Color.blue.opacity(0.28), Color.teal.opacity(0.2), Color.purple.opacity(0.22)],
                startPoint: .topLeading,
                endPoint: .bottomTrailing
            )
            .ignoresSafeArea()

            VStack(spacing: 16) {
                header
                controls
                preview
                footer
            }
            .padding(20)
        }
        .onChange(of: viewModel.outputFormat) { _ in viewModel.recalculateEstimate() }
        .onChange(of: viewModel.quality) { _ in viewModel.recalculateEstimate() }
    }

    private var header: some View {
        GlassPanel {
            HStack {
                VStack(alignment: .leading, spacing: 4) {
                    Text("Minify")
                        .font(.largeTitle.bold())
                    Text("Bulk image compression with a clean, native SwiftUI workflow")
                        .foregroundStyle(.secondary)
                }
                Spacer()
                Button("Pick Images") { viewModel.pickImages() }
                    .buttonStyle(.borderedProminent)
                Button("Clear") { viewModel.clearImages() }
                    .buttonStyle(.bordered)
            }
        }
    }

    private var controls: some View {
        GlassPanel {
            VStack(alignment: .leading, spacing: 14) {
                HStack {
                    Text("Output Format")
                    Spacer()
                    Picker("Format", selection: $viewModel.outputFormat) {
                        ForEach(OutputFormat.allCases) { format in
                            Text(format.displayName).tag(format)
                        }
                    }
                    .labelsHidden()
                    .pickerStyle(.segmented)
                    .frame(width: 380)
                }

                HStack {
                    Text("Quality")
                    Slider(value: $viewModel.quality, in: 0.05...1.0)
                    Text("\(Int(viewModel.quality * 100))%")
                        .monospacedDigit()
                        .frame(width: 52, alignment: .trailing)
                }

                Divider().overlay(.white.opacity(0.12))

                HStack(spacing: 24) {
                    stat("Images", value: "\(viewModel.images.count)")
                    stat("Estimated Output", value: ByteCountFormatter.string(fromByteCount: viewModel.estimatedSize, countStyle: .file))
                }
            }
        }
    }

    private var preview: some View {
        GlassPanel {
            VStack(alignment: .leading, spacing: 8) {
                Text("Selected Files")
                    .font(.headline)

                if viewModel.images.isEmpty {
                    Text("No images selected.")
                        .foregroundStyle(.secondary)
                        .frame(maxWidth: .infinity, minHeight: 140)
                } else {
                    ScrollView {
                        LazyVStack(alignment: .leading, spacing: 6) {
                            ForEach(viewModel.images) { image in
                                HStack {
                                    Image(systemName: "photo")
                                        .foregroundStyle(.cyan)
                                    Text(image.url.lastPathComponent)
                                        .lineLimit(1)
                                    Spacer()
                                    Text(ByteCountFormatter.string(fromByteCount: image.byteCount, countStyle: .file))
                                        .foregroundStyle(.secondary)
                                        .monospacedDigit()
                                }
                                .padding(.vertical, 3)
                            }
                        }
                    }
                    .frame(minHeight: 180)
                }
            }
        }
    }

    private var footer: some View {
        GlassPanel {
            VStack(alignment: .leading, spacing: 10) {
                HStack {
                    Button(viewModel.isConverting ? "Converting..." : "Convert All") {
                        viewModel.convertAll()
                    }
                    .buttonStyle(.borderedProminent)
                    .disabled(viewModel.isConverting || viewModel.images.isEmpty)

                    Text(viewModel.statusMessage)
                        .foregroundStyle(.secondary)

                    Spacer()
                }

                if let error = viewModel.lastError {
                    Text(error)
                        .foregroundStyle(.red)
                }

                if !viewModel.conversionResults.isEmpty {
                    let inTotal = viewModel.conversionResults.reduce(Int64(0)) { $0 + $1.originalBytes }
                    let outTotal = viewModel.conversionResults.reduce(Int64(0)) { $0 + $1.outputBytes }
                    Text("Result: \(ByteCountFormatter.string(fromByteCount: inTotal, countStyle: .file)) → \(ByteCountFormatter.string(fromByteCount: outTotal, countStyle: .file))")
                        .font(.footnote)
                        .foregroundStyle(.secondary)
                }
            }
        }
    }

    private func stat(_ title: String, value: String) -> some View {
        VStack(alignment: .leading, spacing: 2) {
            Text(title)
                .font(.caption)
                .foregroundStyle(.secondary)
            Text(value)
                .font(.headline)
                .monospacedDigit()
        }
    }
}

private struct GlassPanel<Content: View>: View {
    @ViewBuilder var content: Content

    var body: some View {
        content
            .padding(16)
            .background(.ultraThinMaterial, in: RoundedRectangle(cornerRadius: 18, style: .continuous))
            .overlay(
                RoundedRectangle(cornerRadius: 18, style: .continuous)
                    .stroke(.white.opacity(0.22), lineWidth: 1)
            )
            .shadow(color: .black.opacity(0.15), radius: 16, x: 0, y: 10)
    }
}
"}

